INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0de271ae-592c-464d-a2a6-2c04226b6d37',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ray Train — Experiment Tracking with report(), Checkpoints, and ResultGrid$escape$,
  $escape$Ray Train's `train.report()` is your single call for logging metrics, params, and artifacts mid-training. Every worker calls it; Ray aggregates across distributed workers automatically. Pair it with `train.Checkpoint` to snapshot model state alongside metrics — the checkpoint is co-located with the report, so you never lose the weights that produced a given score.

For hyperparameter sweeps, Ray Tune wraps Train and stores every trial's results in a `ResultGrid`. Call `result_grid.get_best_result(metric='val_loss', mode='min')` to surface the top run, then `best.config` for its params and `best.checkpoint` to restore weights directly.

Compare runs programmatically via `result_grid.get_dataframe()` — it returns a pandas DataFrame with one row per trial, columns for every reported metric and sampled config key. Filter, sort, and plot without leaving Python. For artifact tracking, store file paths or serialized objects inside the checkpoint directory via `Checkpoint.from_directory()`, keeping artifacts version-locked to the exact trial that produced them.$escape$,
  $escape$import ray
from ray import train, tune
from ray.train import Checkpoint
import tempfile, os, torch

def train_fn(config):
    model = build_model(config["lr"])
    for epoch in range(10):
        loss = train_epoch(model, config)
        with tempfile.TemporaryDirectory() as tmpdir:
            torch.save(model.state_dict(), os.path.join(tmpdir, "model.pt"))
            checkpoint = Checkpoint.from_directory(tmpdir)
            train.report({"val_loss": loss, "epoch": epoch}, checkpoint=checkpoint)

tuner = tune.Tuner(train_fn, param_space={"lr": tune.loguniform(1e-4, 1e-1)})
result_grid = tuner.fit()

best = result_grid.get_best_result(metric="val_loss", mode="min")
print(best.config, best.metrics)
df = result_grid.get_dataframe()  # all trials as pandas DataFrame$escape$,
