INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a9b4b859-5ba6-4854-aaa1-0cb000886648',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ray + MLflow — Distributed Experiment Tracking with MLflowLoggerCallback$escape$,
  $escape$Ray Tune natively integrates with MLflow via `MLflowLoggerCallback`, automatically syncing trial metrics, hyperparameters, and artifacts to your MLflow tracking server without manual `mlflow.log_metric()` calls inside each worker. Each Ray trial maps to a distinct MLflow run under a shared experiment, preserving the full hyperparameter sweep in one place.

Configure the callback with `tracking_uri` pointing to your remote server and `registry_uri` for the model registry. After tuning, promote the best checkpoint using `mlflow.register_model()` referencing the artifact URI stored in the best trial's MLflow run. For serving, `mlflow models serve -m models:/MyModel/Production` spins up a REST endpoint backed by that registered version.

For Ray Train distributed jobs, use `mlflow.start_run()` only on rank-0 workers — Ray's `train.get_context().get_world_rank()` guards the logging path. Artifacts written to `ray.train.get_context().get_trial_dir()` can be logged to MLflow at job end using `mlflow.log_artifacts()`, keeping distributed checkpoints centralized in the registry.$escape$,
  $escape$import ray
from ray import tune
from ray.air.integrations.mlflow import MLflowLoggerCallback

ray.init()

tuner = tune.Tuner(
    trainable=my_train_fn,
    param_space={"lr": tune.loguniform(1e-4, 1e-1), "batch_size": tune.choice([32, 64])},
    run_config=tune.RunConfig(
        callbacks=[
            MLflowLoggerCallback(
                tracking_uri="http://mlflow-server:5000",
                registry_uri="http://mlflow-server:5000",
                experiment_name="ray-tune-sweep",
                save_artifact=True,
            )
        ]
    ),
)
results = tuner.fit()
print(results.get_best_result(metric="val_loss", mode="min").metrics)$escape$,
  $escape$python$escape$,
