INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b6acea03-c779-4b36-b4a9-e1b05dd56c96',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ray + DVC — Reproducible Distributed Training Pipelines with Data Versioning$escape$,
  $escape$DVC treats Ray training jobs as reproducible pipeline stages — each stage declares its deps, outs, and the command that invokes your Ray script. When you call `dvc repro`, DVC checks content hashes to skip unchanged stages, so only stale stages re-run — no redundant Ray cluster spin-ups.

Define stages in `dvc.yaml`: a `preprocess` stage runs your `ray.data` preprocessing script, its outputs become deps for a `train` stage that launches `ray.train.TorchTrainer`. DVC hashes the processed dataset; if it hasn't changed, the train stage is skipped entirely.

Remote storage (`dvc remote add -d myremote s3://bucket/ray-artifacts`) pushes model checkpoints and Ray Train checkpoints to S3/GCS, decoupled from Ray's own artifact storage. Team members pull exact data versions with `dvc pull` before running `dvc repro`, guaranteeing bit-identical inputs.

`dvc params.yaml` externalizes Ray Train hyperparameters — `num_workers`, `use_gpu`, learning rate — so every experiment is versioned alongside code and data. `dvc metrics show` surfaces `metrics.json` written by your Ray `train.report()` callback, making experiment comparison trivial without a separate MLflow server.$escape$,
  $escape$# dvc.yaml
stages:
  preprocess:
    cmd: python preprocess.py
    deps: [data/raw/, preprocess.py]
    outs: [data/processed/]

  train:
    cmd: python train.py
    deps: [data/processed/, train.py, params.yaml]
    outs: [models/checkpoint/]
    metrics:
      - metrics.json:
          cache: false

# params.yaml
ray:
  num_workers: 4
  use_gpu: true
  lr: 3e-4

# train.py (excerpt)
import ray.train as train
from ray.train.torch import TorchTrainer
from ray.train import ScalingConfig
import yaml, json

params = yaml.safe_load(open("params.yaml"))["ray"]
trainer = TorchTrainer(
    train_loop_per_worker=train_fn,
    scaling_config=ScalingConfig(
        num_workers=params["num_workers"],
        use_gpu=params["use_gpu"]
    ),
)
result = trainer.fit()
json.dump({"loss": result.metrics["loss"]}, open("metrics.json", "w"))$escape$,
  $escape$python$escape$,
