INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fe643622-3396-4261-adee-823becbf9ef6',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ray + MLflow Model Registry — Staging, Production, and Approval Workflows$escape$,
  $escape$Ray Train doesn't ship its own model registry — the idiomatic approach is MLflow, which integrates directly via `ray.air.integrations.mlflow`. After a Ray Train run, you log the checkpoint to MLflow and register it under a named model. From there, a model version lives in one of three stages: `None`, `Staging`, or `Production`. Promotion is explicit: you call `client.transition_model_version_stage()` — no automatic promotion happens without code. This is your approval gate. For team workflows, wrap the transition in a CI step that requires a reviewer to merge a PR or trigger a pipeline, keeping the registry as your source of truth. Ray Serve then loads the model by fetching the `Production` alias at startup, so rolling back is just demoting the current version and promoting the previous one — no redeployment needed. Use `MlflowLoggerCallback` in `RunConfig` to wire logging automatically during distributed training runs.$escape$,
  $escape$import mlflow
from mlflow.tracking import MlflowClient

client = MlflowClient()

# After Ray Train run — register the logged model
run_id = "<your_ray_train_run_id>"
model_uri = f"runs:/{run_id}/model"
result = mlflow.register_model(model_uri, "my-ray-model")

# Promote to Staging (manual approval step in CI)
client.transition_model_version_stage(
    name="my-ray-model",
    version=result.version,
    stage="Staging"
)

# After validation — promote to Production
client.transition_model_version_stage(
    name="my-ray-model",
    version=result.version,
    stage="Production"
)

# Ray Serve deployment pulls Production at startup
production_uri = "models:/my-ray-model/Production"
model = mlflow.pyfunc.load_model(production_uri)$escape$,
  $escape$python$escape$,
