INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7aead0ca-f6c7-4241-a887-d669815a5a53',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ray Serve + ONNX — Deploying Cross-Framework Models at Scale$escape$,
  $escape$ONNX gives you a single serialized graph that any runtime can execute — but in Ray, the deployment pattern matters as much as the format. Export your PyTorch model once: `torch.onnx.export(model, dummy_input, 'model.onnx', opset_version=17, dynamic_axes={'input': {0: 'batch_size'}})`. The `dynamic_axes` arg is critical — without it, Ray Serve replicas reject variable batch sizes at inference time.

Inside a `@serve.deployment`, load the ONNX session in `__init__` so each replica initializes its own `ort.InferenceSession` rather than sharing state across workers. Use `providers=['CUDAExecutionProvider', 'CPUExecutionProvider']` to let ONNX Runtime fall back gracefully when a Ray actor lands on a CPU-only node.

For batching, wrap your deployment with `@serve.deployment(max_ongoing_requests=100)` and use `handle.options(stream=False).remote(batch)` to feed batched numpy arrays. Ray's actor model means each replica holds the session in-process — no serialization overhead per request. Profile with `ray timeline` to catch cold-start latency on first replica initialization, which dominates p99 on autoscaled deployments.$escape$,
  $escape$import ray
from ray import serve
import onnxruntime as ort
import numpy as np

@serve.deployment(num_replicas=2, ray_actor_options={"num_gpus": 0.5})
class ONNXModel:
    def __init__(self, model_path: str):
        self.session = ort.InferenceSession(
            model_path,
            providers=["CUDAExecutionProvider", "CPUExecutionProvider"]
        )
        self.input_name = self.session.get_inputs()[0].name

    async def __call__(self, request):
        data = np.array(await request.json(), dtype=np.float32)
        return self.session.run(None, {self.input_name: data})[0].tolist()

app = ONNXModel.bind(model_path="/models/model.onnx")
serve.run(app, route_prefix="/infer")$escape$,
  $escape$python$escape$,
