INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '97509fec-b5af-402f-8495-2483b990665c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ray + TensorRT — Parallelizing Engine Builds Across Precision Tiers$escape$,
  $escape$TensorRT engine building is GPU-bound and sequential by default — building FP32, FP16, and INT8 variants of a single model can take 10–30 minutes total. Ray's `@ray.remote(num_gpus=1)` decorator turns each precision build into a parallel task, scheduling them across GPU workers simultaneously and cutting total wall time to the slowest single variant.

INT8 quantization requires a calibration dataset passed to TensorRT's `Int8Calibrator` inside the remote task — Ray's object store handles distributing calibration tensors to each worker without redundant copies. FP16 yields ~1.5x latency improvement with negligible accuracy loss; INT8 pushes to ~3x but requires calibration data that mirrors your production distribution closely.

Once built, serialize each engine to bytes and collect via `ray.get()`. For serving, wrap each engine in a Ray Serve deployment with `@serve.deployment`, then front them with a `Router` deployment to A/B route traffic by precision tier. Ray Serve's `num_replicas` and `ray_actor_options={"num_gpus": 1}` ensure each replica holds an isolated CUDA context, eliminating engine-switching overhead between requests.$escape$,
  $escape$import ray, tensorrt as trt
@ray.remote(num_gpus=1)
def build_trt_engine(onnx_path: str, precision: str) -> bytes:
    builder = trt.Builder(trt.Logger(trt.Logger.WARNING))
    config = builder.create_builder_config()
    if precision == "fp16":
        config.set_flag(trt.BuilderFlag.FP16)
    elif precision == "int8":
        config.set_flag(trt.BuilderFlag.INT8)
    net = builder.create_network(1 << int(trt.NetworkDefinitionCreationFlag.EXPLICIT_BATCH))
    trt.OnnxParser(net, trt.Logger()).parse_from_file(onnx_path)
    return builder.build_serialized_network(net, config)
ray.init()
futures = {p: build_trt_engine.remote("model.onnx", p) for p in ["fp32", "fp16", "int8"]}
engines = {p: ray.get(f) for p, f in futures.items()}$escape$,
  $escape$python$escape$,
