INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2f0dd0e5-bddc-4923-882f-433dd2369ccb',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ray — Distributed Training, HPO with Tune, and Serving with Ray Serve$escape$,
  $escape$Ray's actor model lets you scale ML workloads across a cluster without rewriting your training logic. With `ray.remote`, any Python function or class becomes a distributed task or stateful actor. For distributed training, Ray Train wraps your existing PyTorch loop inside a `TorchTrainer`, automatically handling device placement and gradient synchronization across workers.

Ray Tune sits on top of Ray Train for hyperparameter optimization. Define a search space with `tune.loguniform` or `tune.choice`, pick a scheduler like `ASHAScheduler` to prune bad trials early, and Tune distributes trials across your cluster — each trial runs as an independent Ray actor. Results are logged to the `trial_dir` and can be passed directly to `result.get_best_result()`.

Ray Serve closes the loop for deployment. A `@serve.deployment` decorator turns any class into a scalable, autoscaling replica group. You can compose multiple deployments using `DeploymentHandle` for chained inference pipelines — e.g., preprocessing → model → postprocessing — all within a single Serve application. Replicas share the Ray cluster, so your serving layer can coexist with background retraining jobs without separate infrastructure.$escape$,
  $escape$import ray
from ray import tune
from ray.tune.schedulers import ASHAScheduler
from ray.train.torch import TorchTrainer
from ray.train import ScalingConfig
from ray import serve

# Distributed training
trainer = TorchTrainer(
    train_loop_per_worker=train_fn,
    scaling_config=ScalingConfig(num_workers=4, use_gpu=True),
)

# HPO with Tune
tuner = tune.Tuner(
    trainer,
    param_space={"train_loop_config": {"lr": tune.loguniform(1e-4, 1e-1)}},
    tune_config=tune.TuneConfig(scheduler=ASHAScheduler(), num_samples=20),
)
best = tuner.fit().get_best_result(metric="val_loss", mode="min")

# Serving
@serve.deployment(num_replicas=2, ray_actor_options={"num_gpus": 1})
class ModelServer:
    def __init__(self):
        self.model = load_model(best.checkpoint)

    async def __call__(self, request):
        data = await request.json()
        return self.model.predict(data["input"])

serve.run(ModelServer.bind())$escape$,
  $escape$python$escape$,
