INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '292eedbb-60eb-4624-a19b-cf76069799ed',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ray Tune — Grid vs Random vs Bayesian Search with Early Stopping$escape$,
  $escape$Ray Tune unifies all three HPO strategies under a single `tune.run()` interface. Grid search (`tune.grid_search`) exhaustively evaluates every combination — reliable but exponentially expensive. Random search samples from distributions (`tune.uniform`, `tune.loguniform`) and often matches grid quality at a fraction of the cost. Bayesian search via `tune.search.bayesopt.BayesOptSearch` or `OptunaSearch` builds a surrogate model of the loss surface, directing trials toward promising regions — ideal when evaluations are expensive.

The real multiplier is pairing any searcher with a `TrialScheduler`. ASHA (`AsyncHyperBandScheduler`) aggressively terminates underperforming trials using successive halving, while PBT (`PopulationBasedTraining`) mutates hyperparameters mid-training. Combine `OptunaSearch` with `ASHAScheduler` for efficient Bayesian-guided search with early stopping — Optuna proposes candidates, ASHA kills bad ones early. Resources are allocated per trial via `tune.with_resources`, ensuring GPU utilization stays high across the Ray cluster. Use `tune.ResultGrid` to inspect Pareto-optimal trials post-run.$escape$,
  $escape$import ray
from ray import tune
from ray.tune.search.optuna import OptunaSearch
from ray.tune.schedulers import ASHAScheduler

def train(config):
    for epoch in range(10):
        loss = (config["lr"] - 0.01) ** 2 + config["wd"] * 0.1
        tune.report(loss=loss)

tuner = tune.Tuner(
    tune.with_resources(train, resources={"cpu": 2}),
    tune_config=tune.TuneConfig(
        search_alg=OptunaSearch(),
        scheduler=ASHAScheduler(metric="loss", mode="min"),
        num_samples=40,
    ),
    param_space={"lr": tune.loguniform(1e-4, 1e-1), "wd": tune.uniform(0, 0.1)},
)
results = tuner.fit()
print(results.get_best_result(metric="loss", mode="min").config)$escape$,
  $escape$python$escape$,
