INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '03f05b51-524b-4ae9-9299-ab50c6091d0c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ray Serve — Batching, Latency SLAs, and REST Inference at Scale$escape$,
  $escape$Ray Serve turns any Python callable into a production REST endpoint with built-in request batching and latency controls. Deploy a deployment with `@serve.deployment` and expose it via `serve.run()` — Ray handles HTTP routing, replica scaling, and load balancing automatically.

For inference throughput, `@serve.batch` aggregates concurrent requests into a single forward pass. Set `max_batch_size` and `batch_wait_timeout_s` to tune the latency/throughput tradeoff: lower timeout favors p99 latency, higher timeout maximizes GPU utilization.

Latency SLAs are enforced via `autoscaling_config` — set `target_num_ongoing_requests_per_replica` to trigger scale-out before queues build. Pair with `max_replicas` to cap cost. For strict p99 budgets, monitor `serve_deployment_request_latency_ms` in the built-in Prometheus metrics endpoint (`/metrics`).

Use `DeploymentHandle` for model chaining (preprocessing → inference → postprocessing) without leaving the Ray cluster — no extra HTTP hops, just in-process async calls between deployments.$escape$,
  $escape$from ray import serve
from ray.serve.handle import DeploymentHandle
import numpy as np

@serve.deployment(
    num_replicas=2,
    autoscaling_config={"min_replicas": 1, "max_replicas": 8, "target_num_ongoing_requests_per_replica": 5},
)
class InferenceModel:
    def __init__(self):
        self.model = load_model()  # your model here

    @serve.batch(max_batch_size=32, batch_wait_timeout_s=0.01)
    async def __call__(self, inputs: list[np.ndarray]) -> list[float]:
        return self.model.predict(np.stack(inputs)).tolist()

app = InferenceModel.bind()
serve.run(app, route_prefix="/predict")$escape$,
  $escape$python$escape$,
