INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0846111d-007f-4a5a-825a-9f7bed6484fe',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ray Serve — Monitoring Prediction Drift and Data Drift in Production$escape$,
  $escape$Ray Serve deployments expose replica-level metrics via `ray.util.metrics`, which Prometheus scrapes automatically — no sidecar needed. For prediction drift, attach a `Histogram` to each `@serve.deployment` replica to bucket live prediction scores. Buffer predictions per replica and compute Population Stability Index (PSI) against your baseline distribution; PSI > 0.2 signals significant drift requiring a model refresh.

For data drift, validate incoming feature distributions upstream using a Ray Data pipeline before requests hit the model replica. Pipe raw payloads through `ray.data.Dataset` with `describe()` and z-score checks to catch covariate shift before it silently degrades accuracy.

Performance degradation is tracked via built-in Serve metrics: `serve_num_router_requests`, `serve_deployment_processing_latency_ms`, and `serve_replica_error_rate` emit out-of-the-box. Combine these with a custom PSI `Gauge` in Grafana for a unified monitoring dashboard. When PSI spikes, use a background Ray actor as a retraining coordinator — the degraded replica continues serving stale predictions while the new model is staged and hot-swapped via `serve.run()` with zero downtime.$escape$,
  $escape$from ray import serve
from ray.util.metrics import Histogram, Gauge
import numpy as np

pred_hist = Histogram("pred_score", boundaries=[i / 10 for i in range(11)])
psi_gauge = Gauge("prediction_psi", tag_keys=("model_version",))

@serve.deployment(num_replicas=2, ray_actor_options={"num_cpus": 1})
class DriftAwareModel:
    def __init__(self, baseline: list[float]):
        self.baseline_hist = np.array(baseline)
        self.buffer: list[float] = []

    async def __call__(self, req):
        payload = await req.json()
        score = float(self.model.predict_proba(payload["features"])[0][1])
        pred_hist.observe(score)
        self.buffer.append(score)
        if len(self.buffer) >= 200:
            current, _ = np.histogram(self.buffer, bins=10, density=True)
            psi = float(np.sum((current - self.baseline_hist) * np.log((current + 1e-8) / (self.baseline_hist + 1e-8))))
            psi_gauge.set(psi, tags={"model_version": "v2"})
            self.buffer.clear()
        return {"score": score}$escape$,
  $escape$python$escape$,
