INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a7be6340-1db4-4649-ac7f-387a6730dc20',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ray — CI/CD Pipelines for ML with Automated Retraining and Evaluation Gates$escape$,
  $escape$Ray Pipelines don't exist natively, but Ray's composable primitives let you build robust CI/CD workflows for ML. Use `ray.init()` with a remote cluster address to run retraining jobs on-demand from GitHub Actions or any CI runner. Wrap your training logic in a `@ray.remote` task and chain it with an evaluation gate: if the new model's metric doesn't exceed the baseline stored in Ray's object store or a model registry, the pipeline fails fast without deploying.

For automated retraining, `ray job submit` is the idiomatic entry point — it packages your working directory and submits to the Ray cluster without manual SSH. Use `ray.get()` to block on evaluation results and assert thresholds before promoting. Ray Train's `Checkpoint` API integrates cleanly here: store trial checkpoints in cloud storage, load the best checkpoint in your gate step, and only push to your serving layer (e.g., Ray Serve) if accuracy and latency SLOs are met. This gives you a fully auditable, reproducible retraining loop that runs entirely within Ray's distributed runtime.$escape$,
  $escape$import ray
from ray import train
from ray.job_submission import JobSubmissionClient

client = JobSubmissionClient("http://<ray-cluster-head>:8265")

job_id = client.submit_job(
    entrypoint="python train.py",
    runtime_env={"working_dir": ".", "pip": ["xgboost", "scikit-learn"]},
)

# Poll until complete
status = client.get_job_status(job_id)
assert status == "SUCCEEDED", f"Training job failed: {status}"

# Evaluation gate — load best checkpoint and assert threshold
@ray.remote
def evaluate_gate(checkpoint_path: str, baseline_accuracy: float) -> bool:
    from ray.train import Checkpoint
    checkpoint = Checkpoint(checkpoint_path)
    with checkpoint.as_directory() as d:
        import joblib, numpy as np
        model = joblib.load(f"{d}/model.pkl")
        acc = model.score(X_test, y_test)
        return acc > baseline_accuracy

passed = ray.get(evaluate_gate.remote("s3://my-bucket/checkpoints/latest", 0.91))
if not passed:
    raise SystemExit("Evaluation gate failed — deployment blocked")$escape$,
  $escape$python$escape$,
