INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd4057bfe-c1c1-4cf4-9b63-cf3e553f57f5',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ray Feature Stores — Online vs Offline Features with Feast and Ray Data$escape$,
  $escape$Feature stores split into two paths: offline (batch, training-time) and online (low-latency, inference-time). Ray bridges both natively. Feast uses Ray Data as its offline materialization engine — when you call `feast materialize`, it spins up a Ray cluster to compute features across your dataset in parallel, writing results to an online store like Redis. For online serving, Ray Serve actors cache feature vectors in-memory, giving sub-millisecond retrieval without hitting the DB on every request. The key distinction: offline features tolerate minutes of staleness and optimize for throughput; online features must be fresh (typically <15 min TTL) and optimize for p99 latency. With Ray, you can share the same feature transformation logic — a plain Python function — across both paths using `@ray.remote` for offline batch jobs and a Ray Serve deployment for online lookup. This eliminates training-serving skew, the #1 silent killer of ML model performance in production. Point-in-time joins for training data are handled via `ray.data.Dataset.sort()` before the feature merge step.$escape$,
  $escape$import ray
from ray import serve
from feast import FeatureStore

# Offline: materialize features using Ray Data as compute engine
# feast materialize uses Ray under the hood when provider is set to "local" + Ray
store = FeatureStore(repo_path="./feature_repo")

@ray.remote
def compute_user_features(user_ids: list) -> dict:
    return store.get_historical_features(
        entity_df=user_ids,
        features=["user_stats:click_rate", "user_stats:session_len"]
    ).to_df().to_dict()

# Online: Ray Serve actor caches online features
@serve.deployment(num_replicas=2, ray_actor_options={"num_cpus": 0.5})
class OnlineFeatureServer:
    def __init__(self):
        self.store = FeatureStore(repo_path="./feature_repo")

    async def __call__(self, user_id: str) -> dict:
        return self.store.get_online_features(
            features=["user_stats:click_rate"],
            entity_rows=[{"user_id": user_id}]
        ).to_dict()$escape$,
  $escape$python$escape$,
