INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e6380be0-cb2c-47ca-8bcf-efde277c8aed',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ray Serve — A/B Testing Models with Shadow, Canary, and Champion/Challenger$escape$,
  $escape$Ray Serve lets you implement all three model evaluation patterns natively via traffic splitting and deployment handles.

For canary releases, define a router deployment that probabilistically routes requests between champion and challenger using `DeploymentHandle`. Set the challenger weight low (e.g. 5%) and ramp it up as metrics validate performance.

For shadow deployment, fan out every request to both models — serve the champion's response to the client while logging the challenger's output asynchronously via `asyncio.gather`. No user impact, full side-by-side comparison.

For champion/challenger, use `serve.deployment` with named replicas and a stateful router that tracks per-model latency and accuracy signals, then shifts traffic using `deployment_handle.options(use_new_handle_api=True)` at runtime without redeployment.

All deployments share Ray's actor model — each model runs in isolated replicas with independent autoscaling via `ray_actor_options`. Traffic weights update live through `serve.run()` re-application on the same app name, making zero-downtime promotion trivial.$escape$,
  $escape$import ray
from ray import serve
from ray.serve.handle import DeploymentHandle
import asyncio, random

@serve.deployment
class ShadowRouter:
    def __init__(self, champion: DeploymentHandle, challenger: DeploymentHandle):
        self.champion = champion
        self.challenger = challenger

    async def __call__(self, request):
        data = await request.json()
        champion_resp, _ = await asyncio.gather(
            self.champion.predict.remote(data),
            self.challenger.predict.remote(data)  # shadow, result discarded
        )
        return champion_resp

@serve.deployment(ray_actor_options={"num_cpus": 1})
class CanaryRouter:
    def __init__(self, champion: DeploymentHandle, challenger: DeploymentHandle, canary_pct: float = 0.05):
        self.champion, self.challenger, self.pct = champion, challenger, canary_pct

    async def __call__(self, request):
        data = await request.json()
        handle = self.challenger if random.random() < self.pct else self.champion
        return await handle.predict.remote(data)$escape$,
  $escape$python$escape$,
