INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd27e6570-b193-4d68-b488-7f280a93f259',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ray Data Pipelines — Feature Engineering, Validation, and Drift Detection at Scale$escape$,
  $escape$Ray Data's `map_batches()` is the workhorse for production feature engineering pipelines. Unlike single-node Pandas transforms, `map_batches()` distributes work across your cluster while preserving schema and lineage. Chain it with `.filter()` for inline validation — reject rows with nulls, out-of-range values, or schema mismatches before they poison downstream models.

For drift detection, embed a stateful Ray Actor as a batch UDF. The actor holds a reference distribution (mean, std, quantiles) computed on training data and emits drift alerts when live batch statistics diverge beyond a configurable threshold. Using `ActorPoolStrategy` with `map_batches()` keeps the reference in-memory across batches without repeated deserialization — critical for high-throughput pipelines.

Pair this with `ray.data.DataContext.get_current().execution_options` to tune memory pressure and backpressure. The pipeline stays lazy until `.write_parquet()` or `.iter_batches()` triggers execution, so you compose transforms without materializing intermediate datasets. For scheduled retraining, wrap the pipeline in a Ray workflow using `ray.workflow.run()` to get checkpointing and fault tolerance out of the box.$escape$,
  $escape$import ray
import numpy as np

@ray.remote
class DriftDetector:
    def __init__(self, ref_mean, ref_std):
        self.ref_mean, self.ref_std = ref_mean, ref_std

    def check(self, batch: dict) -> dict:
        live_mean = np.mean(batch["feature"])
        drift = abs(live_mean - self.ref_mean) / (self.ref_std + 1e-8)
        batch["drift_score"] = [float(drift)] * len(batch["feature"])
        return batch

detector = DriftDetector.remote(ref_mean=0.5, ref_std=0.1)

ds = (
    ray.data.read_parquet("s3://features/live/")
    .filter(lambda r: r["feature"] is not None)
    .map_batches(lambda b: ray.get(detector.check.remote(b)), batch_format="numpy")
)
ds.write_parquet("s3://features/validated/")$escape$,
  $escape$python$escape$,
