INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f9cbe72e-ca13-4899-a3cb-e394c364ce75',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ray Train on Spot GPUs — Fault-Tolerant Distributed Training with Zero Waste$escape$,
  $escape$Spot/preemptible GPUs can cut training costs by 60–90%, but preemptions will kill your run unless Ray Train's fault tolerance is configured correctly. The key lever is `FailureConfig(max_failures=-1)` inside `RunConfig`, which tells Ray to restart a trial indefinitely on worker failure — not just retry once. Pair this with periodic checkpointing via `ray.train.report({}, checkpoint=Checkpoint.from_directory(ckpt_dir))` so each restart resumes from the last saved state, not epoch zero.

For placement, use `ScalingConfig(num_workers=4, use_gpu=True, resources_per_worker={"GPU": 1})` and let Ray's autoscaler provision spot nodes. Set `TRAIN_ENABLE_WORKER_SPREAD_ENV_VAR=1` to spread workers across availability zones — this reduces the chance of a full-cluster preemption wiping all workers simultaneously.

To cap runaway costs, set `time_budget_s` in `TuneConfig` when using Ray Tune alongside Train. Combine with `SyncConfig` pointing to Azure Blob or S3 so checkpoints survive node termination and are immediately accessible on respawned workers. This pattern reliably trains multi-GPU jobs at spot pricing with no manual restart logic.$escape$,
  $escape$from ray.train.torch import TorchTrainer
from ray.train import ScalingConfig, RunConfig, FailureConfig, CheckpointConfig
import ray.train
from ray.train import Checkpoint
import os

def train_fn(config):
    ckpt = ray.train.get_checkpoint()
    start_epoch = 0
    if ckpt:
        with ckpt.as_directory() as d:
            start_epoch = int(open(os.path.join(d, "epoch")).read())

    for epoch in range(start_epoch, config["epochs"]):
        # ... training logic ...
        ckpt_dir = f"/tmp/ckpt/epoch_{epoch}"
        os.makedirs(ckpt_dir, exist_ok=True)
        open(os.path.join(ckpt_dir, "epoch"), "w").write(str(epoch + 1))
        ray.train.report(
            {"epoch": epoch},
            checkpoint=Checkpoint.from_directory(ckpt_dir)
        )

trainer = TorchTrainer(
    train_fn,
    train_loop_config={"epochs": 50},
    scaling_config=ScalingConfig(num_workers=4, use_gpu=True),
    run_config=RunConfig(
        failure_config=FailureConfig(max_failures=-1),
        checkpoint_config=CheckpointConfig(num_to_keep=2),
    ),
)
trainer.fit()$escape$,
  $escape$python$escape$,
